using System;
using System.Diagnostics;
using System.IO;
using System.Linq;

public static class PdfGenerator
{
    public static bool GeneratePdfFromHtml(string htmlFilePath, string pdfFilePath, PdfOptions options)
    {
        if (string.IsNullOrEmpty(htmlFilePath) || string.IsNullOrEmpty(pdfFilePath))
            throw new ArgumentException("HTML file path and PDF file path cannot be null or empty");
            
        if (!File.Exists(htmlFilePath))
            throw new FileNotFoundException("HTML file not found", htmlFilePath);
            
        if (options == null)
            options = new PdfOptions();
            
        var processStartInfo = new ProcessStartInfo
        {
            FileName = "wkhtmltopdf.exe",
            Arguments = BuildArguments(htmlFilePath, pdfFilePath, options),
            UseShellExecute = false,
            RedirectStandardOutput = true,
            RedirectStandardError = true,
            CreateNoWindow = true
        };
        
        try
        {
            using (var process = Process.Start(processStartInfo))
            {
                process.WaitForExit();
                return process.ExitCode == 0;
            }
        }
        catch (Exception)
        {
            return false;
        }
    }
    
    private static string BuildArguments(string htmlFilePath, string pdfFilePath, PdfOptions options)
    {
        var arguments = new System.Text.StringBuilder();
        
        // Add page size if valid
        if (IsValidPageSize(options.PageSize))
            arguments.Append($"--page-size {options.PageSize} ");
            
        // Add orientation if valid
        if (IsValidOrientation(options.Orientation))
            arguments.Append($"--orientation {options.Orientation} ");
            
        // Add input and output paths
        arguments.Append($"\"{htmlFilePath}\" ");
        arguments.Append($"\"{pdfFilePath}\"");
        
        return arguments.ToString().Trim();
